"}, {"start": 137.0, "end": 141.0, "text": "Hello?"}, {"start": 143.0, "end": 151.0, "text": "Madam, it\\u2019s been over 40 minutes, and my Tata Nexon EV battery is just 80% charged."}, {"start": 154.0, "end": 157.0, "text": "Thank you."}, {"start": 160.0, "end": 171.0, "text": "The machine should deliver power according to what the car demands."}, {"start": 185.0, "end": 189.0, "text": "We raised a complaint earlier, and the vendor team is coming for maintenance."}, {"start": 191.0, "end": 195.0, "text": "Sir, I\\u2019ll reboot the machine now. Let\\u2019s try charging again."}, {"start": 201.0, "end": 203.0, "text": "Let me know when the machine display turns on."}, {"start": 227.0, "end": 231.0, "text": "Yes, the display is visible on the app."}, {"start": 281.0, "end": 323.0, "text": "The machine currently has no roof, which could cause rain-related problems. We are working on arranging a shed soon."}, {"start": 340.0, "end": 342.0, "text": "No, the machine is showing a red light."}, {"start": 361.0, "end": 363.0, "text": "Now it shows available."}, {"start": 363.0, "end": 371.0, "text": "I\\u2019ll start the charging now. Please ensure the gun is connected to your car."}, {"start": 393.0, "end": 453.0, "text": "Sir, which charging gun is closer to your car? Gun B? Please connect it to your car. Can you share the OTP? The OTP is 4376."}, {"start": 532.0, "end": 540.0, "text": "Sir, I\\u2019ve plugged in the machine. Please ensure the gun is in your car."}, {"start": 576.0, "end": 586.0, "text": "The charger is showing activity, but it is only working for two minutes."}, {"start": 590.0, "end": 607.0, "text": "Sir, we raised a ticket already, and the machine is connected at 41% charge. We are monitoring it to ensure it doesn\\u2019t disconnect."}, {"start": 714.0, "end": 723.0, "text": "Sir, the charging should continue. If there are further issues, please contact customer service."}, {"start": 735.0, "end": 737.0, "text": "Thank you, sir."}]	null	\N	{"analysed"